import { readFileSync } from 'node:fs';
let data;
try { data = JSON.parse(readFileSync('brief.json', 'utf8')); } catch { process.exit(1); }
if (!Array.isArray(data.findings) || data.findings.length === 0) process.exit(1);
if (!Array.isArray(data.sources) || data.sources.length === 0) process.exit(1);
for (const f of data.findings) {
  if (!f || typeof f.claim !== 'string' || f.claim.trim().length < 8) process.exit(1);
  if (typeof f.source_event_id !== 'string' || f.source_event_id.trim().length === 0) process.exit(1);
}
process.exit(0);
